function fetchLatestBooks(){const e=document.querySelector("#latest-books > ul");if(e&&kroTtfe?.currentId&&kroTtfe.apiUrl){fetch(`${kroTtfe.apiUrl}/book?per_page=20&exclude=${kroTtfe.currentId}&_embed`).then(e=>{if(!e.ok)throw new Error("Fetching data error");return e.json()}).then(r=>{if(r.length===0){e.parentElement.remove();return}r.forEach(r=>{let t="";const n=r?._embedded?.["wp:term"]?.[0]??[];const o=n.map(e=>e.name).join(", ")||"";if(r.title?.rendered){t+=`<strong>"${r.title.rendered}"</strong>`}if(r.excerpt?.rendered){t+=r.excerpt.rendered}if(o){t+=`<p><strong>Genres:</strong> ${o}</p>`}if(r.link){t+=`<a href="${r.link}" target="_blank">Read more...</a>`}if(t){e.innerHTML+=`<li>${t}</li>`}})}).catch(e=>console.error("REST API Error:",e))}}window.addEventListener("load",e=>{fetchLatestBooks()});